const raw = $json.filepath;
if (!raw || raw.trim() === '') {
  return [];
}
const lines = raw.split('\n').map(l => l.trim()).filter(l => l.length > 0);
return lines.map(line => ({ json: { filepath: line } }));

const stdout = $json.stdout || '';
const stderr = $json.stderr || '';
const exitCode = $json.exitCode;

const accountMatch = stdout.match(/account_id:\s*([\w_]+)/);
const companyMatch = stdout.match(/company:\s*(.+)/);
const issueMatch = stdout.match(/issue_url:\s*(https:\/\/[^\s]+)/);

return [{
  json: {
    filepath: $json.filepath,
    status: exitCode === 0 ? 'success' : 'error',
    account_id: accountMatch ? accountMatch[1] : 'unknown',
    company_name: companyMatch ? companyMatch[1].trim() : 'unknown',
    issue_url: issueMatch ? issueMatch[1] : null,
    stdout: stdout,
    stderr: stderr,
    exit_code: exitCode
  }
}];

// SUCCESS: log to console and pass through
const item = $json;
console.log(`✓ [Pipeline A] ${item.account_id} | ${item.company_name} | ${item.issue_url}`);
return [{ json: { ...item, logged_at: new Date().toISOString() } }];

// ERROR: append to error log file
const item = $json;
const fs = require('fs');
const logPath = '/data/logs/errors.jsonl';
const entry = JSON.stringify({
  timestamp: new Date().toISOString(),
  pipeline: 'A',
  filepath: item.filepath,
  account_id: item.account_id,
  exit_code: item.exit_code,
  stderr: item.stderr,
  stdout: item.stdout
}) + '\n';
try {
  fs.mkdirSync('/data/logs', { recursive: true });
  fs.appendFileSync(logPath, entry);
} catch(e) {
  console.error('Could not write error log:', e.message);
}
console.error(`✗ [Pipeline A ERROR] ${item.filepath}: ${item.stderr}`);
return [{ json: { ...item, error_logged: true } }];

// Collect all results and print batch summary
const allItems = $input.all();
const total = allItems.length;
const succeeded = allItems.filter(i => i.json.status === 'success').length;
const failed = total - succeeded;

console.log(`\n${'='.repeat(50)}`);
console.log(`PIPELINE A COMPLETE: ${succeeded}/${total} succeeded, ${failed} failed`);
allItems.forEach(item => {
  const icon = item.json.status === 'success' ? '✓' : '✗';
  console.log(`  ${icon} ${item.json.account_id || item.json.filepath}`);
});
console.log('='.repeat(50));

return [{
  json: {
    pipeline: 'A',
    total,
    succeeded,
    failed,
    completed_at: new Date().toISOString(),
    accounts: allItems.map(i => i.json.account_id)
  }
}];
